/**
 * Activation Hook
 * Creates the custom upload directory if it doesn't exist.
 */
function user_file_uploader_activate() {
    $upload_dir = wp_upload_dir();
    $user_files_dir = $upload_dir['basedir'] . '/user-files';

    if (!file_exists($user_files_dir)) {
        wp_mkdir_p($user_files_dir);
    }
}
register_activation_hook(__FILE__, 'user_file_uploader_activate');

