/**
 * Handles the file upload submission.
 */
function user_file_uploader_handle_upload() {
    if (!is_user_logged_in()) {
        wp_send_json_error('User not logged in.');
    }

    if (!isset($_POST['user_file_upload_nonce_field']) || !wp_verify_nonce($_POST['user_file_upload_nonce_field'], 'user_file_upload_nonce')) {
        wp_send_json_error('Nonce verification failed.');
    }

    if (empty($_FILES['user_file_upload']['name'])) {
        wp_send_json_error('No file selected for upload.');
    }

    $current_user_id = get_current_user_id();
    $upload_dir = wp_upload_dir();
    $user_files_dir = $upload_dir['basedir'] . '/user-files/' . $current_user_id;

    // Create user-specific directory if it doesn't exist
    if (!file_exists($user_files_dir)) {
        wp_mkdir_p($user_files_dir);
    }

    $allowed_mimes = array(
        'jpg|jpeg|jpe' => 'image/jpeg',
        'gif'          => 'image/gif',
        'png'          => 'image/png',
        'bmp'          => 'image/bmp',
        'tif|tiff'     => 'image/tiff',
        'webp'         => 'image/webp',
        'pdf'          => 'application/pdf',
        'doc'          => 'application/msword',
        'docx'         => 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
        'xls'          => 'application/vnd.ms-excel',
        'xlsx'         => 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
        'ppt'          => 'application/vnd.ms-powerpoint',
        'pptx'         => 'application/vnd.openxmlformats-officedocument.presentationml.presentation',
        'txt'          => 'text/plain',
        'rtf'          => 'application/rtf',
        'zip'          => 'application/zip',
        'rar'          => 'application/x-rar-compressed',
    );

    $file_info = wp_check_filetype($_FILES['user_file_upload']['name'], $allowed_mimes);

    if (empty($file_info['ext']) || empty($file_info['type'])) {
        wp_send_json_error('Invalid file type. Allowed types: ' . implode(', ', array_keys($allowed_mimes)));
    }

    // Sanitize file name
    $filename = sanitize_file_name($_FILES['user_file_upload']['name']);
    $destination = $user_files_dir . '/' . $filename;

    // Ensure unique file name if it already exists
    $count = 1;
    $original_filename = pathinfo($filename, PATHINFO_FILENAME);
    $extension = pathinfo($filename, PATHINFO_EXTENSION);
    while (file_exists($destination)) {
        $filename = $original_filename . '-' . $count . '.' . $extension;
        $destination = $user_files_dir . '/' . $filename;
        $count++;
    }

    if (move_uploaded_file($_FILES['user_file_upload']['tmp_name'], $destination)) {
        // Save file data to user meta
        $file_data = array(
            'filename'    => $filename,
            'original_name' => $_FILES['user_file_upload']['name'],
            'filepath'    => str_replace($upload_dir['basedir'], $upload_dir['baseurl'], $destination), // URL path
            'upload_time' => current_time('mysql'),
            'description' => sanitize_textarea_field($_POST['file_description']),
            'mime_type'   => $file_info['type'],
            'size'        => $_FILES['user_file_upload']['size'],
        );

        $user_files = get_user_meta($current_user_id, '_user_uploaded_files', true);
        if (!is_array($user_files)) {
            $user_files = array();
        }
        $user_files[] = $file_data;
        update_user_meta($current_user_id, '_user_uploaded_files', $user_files);

        wp_send_json_success(array(
            'message' => 'File uploaded successfully!',
            'files_list' => user_file_uploader_display_files($current_user_id)
        ));
    } else {
        wp_send_json_error('Failed to move uploaded file.');
    }
}
add_action('wp_ajax_user_file_uploader_handle_upload', 'user_file_uploader_handle_upload');
add_action('wp_ajax_nopriv_user_file_uploader_handle_upload', 'user_file_uploader_handle_upload'); // For logged-out users, though we check is_user_logged_in()

/**
 * Displays a list of files uploaded by a specific user.
 *
 * @param int $user_id The ID of the user.
 * @return string HTML list of files.
 */
function user_file_uploader_display_files($user_id) {
    $files = get_user_meta($user_id, '_user_uploaded_files', true);

    if (empty($files) || !is_array($files)) {
        return '<p>No files uploaded yet.</p>';
    }

    ob_start();
    echo '<ul>';
    foreach ($files as $index => $file) {
        $file_url = esc_url($file['filepath']);
        $file_name = esc_html($file['original_name']);
        $description = !empty($file['description']) ? ' (' . esc_html($file['description']) . ')' : '';
        $upload_time = date(get_option('date_format') . ' ' . get_option('time_format'), strtotime($file['upload_time']));

        echo '<li>';
        echo '<a href="' . $file_url . '" target="_blank">' . $file_name . '</a>' . $description;
        echo ' <small>(Uploaded: ' . $upload_time . ')</small>';
        // Add a delete button
        if (get_current_user_id() == $user_id) { // Only allow current user to delete their own files
            echo ' <button class="user-file-delete-button" data-file-index="' . $index . '" data-nonce="' . wp_create_nonce('user_file_delete_nonce') . '">Delete</button>';
        }
        echo '</li>';
    }
    echo '</ul>';

    return ob_get_clean();
}

/**
 * Handles file deletion via AJAX.
 */
function user_file_uploader_handle_delete() {
    if (!is_user_logged_in()) {
        wp_send_json_error('User not logged in.');
    }

    if (!isset($_POST['nonce']) || !wp_verify_nonce($_POST['nonce'], 'user_file_delete_nonce')) {
        wp_send_json_error('Nonce verification failed.');
    }

    $current_user_id = get_current_user_id();
    $file_index = isset($_POST['file_index']) ? intval($_POST['file_index']) : -1;

    if ($file_index < 0) {
        wp_send_json_error('Invalid file index.');
    }

    $user_files = get_user_meta($current_user_id, '_user_uploaded_files', true);

    if (!is_array($user_files) || !isset($user_files[$file_index])) {
        wp_send_json_error('File not found.');
    }

    $file_to_delete = $user_files[$file_index];
    $upload_dir = wp_upload_dir();
    $base_upload_path = $upload_dir['basedir'] . '/user-files/' . $current_user_id . '/';
    $full_file_path = $base_upload_path . $file_to_delete['filename'];

    // Delete file from filesystem
    if (file_exists($full_file_path)) {
        unlink($full_file_path);
    }

    // Remove file data from user meta
    unset($user_files[$file_index]);
    $user_files = array_values($user_files); // Re-index array
    update_user_meta($current_user_id, '_user_uploaded_files', $user_files);

    wp_send_json_success(array(
        'message' => 'File deleted successfully!',
        'files_list' => user_file_uploader_display_files($current_user_id)
    ));
}
add_action('wp_ajax_user_file_uploader_handle_delete', 'user_file_uploader_handle_delete');

